enum TogglAdaptiveColor {
  AdaptiveColorShapeOnLightBackground(0),
  AdaptiveColorShapeOnDarkBackground(1),
  AdaptiveColorTextOnLightBackground(2),
  AdaptiveColorTextOnDarkBackground(3);

  final int value;
  const TogglAdaptiveColor(this.value);

  static TogglAdaptiveColor fromValue(int value) => switch (value) {
    0 => AdaptiveColorShapeOnLightBackground,
    1 => AdaptiveColorShapeOnDarkBackground,
    2 => AdaptiveColorTextOnLightBackground,
    3 => AdaptiveColorTextOnDarkBackground,
    _ => throw ArgumentError('Unknown value for TogglAdaptiveColor: $value'),
  };
}

enum TimelineMenuContextType {
  TimelineMenuContextTypeContinueEntry(0),
  TimelineMenuContextTypeStartEntryFromEnd(1),
  TimelineMenuContextTypeDelete(2),
  TimelineMenuContextTypeChangeFirstEntryStopTime(3),
  TimelineMenuContextTypeChangeLastEntryStartTime(4);

  final int value;
  const TimelineMenuContextType(this.value);

  static TimelineMenuContextType fromValue(int value) => switch (value) {
    0 => TimelineMenuContextTypeContinueEntry,
    1 => TimelineMenuContextTypeStartEntryFromEnd,
    2 => TimelineMenuContextTypeDelete,
    3 => TimelineMenuContextTypeChangeFirstEntryStopTime,
    4 => TimelineMenuContextTypeChangeLastEntryStartTime,
    _ => throw ArgumentError(
      'Unknown value for TimelineMenuContextType: $value',
    ),
  };
}

